// CONFIG
var EXPECTED_SECRET = 'mulligan-secure-8821';
var input = items[0].json;

// 1. HUNT FOR DATA (The "Finder" Logic)
var data = {};

// Strategy A: Is it at the root?
if (input.bookingId) {
    data = input;
}
// Strategy B: Is it inside 'body'?
else if (input.body && input.body.bookingId) {
    data = input.body;
}
// Strategy C: Is 'body' a string we need to parse?
else if (input.body && typeof input.body === 'string') {
    try {
        var parsed = JSON.parse(input.body);
        if (parsed.bookingId) data = parsed;
    } catch (e) {}
}

// 2. VALIDATION (Stop immediately if missing)
if (!data.bookingId) {
    var foundKeys = Object.keys(input).join(", ");
    throw new Error(`CRITICAL: Could not find 'bookingId'. Available keys: [${foundKeys}]`);
}

// 3. SECURITY CHECK
var receivedSecret = data.secret || (input.headers ? input.headers['x-secret'] : '');
if (receivedSecret !== EXPECTED_SECRET) {
     throw new Error(`UNAUTHORIZED: Invalid Secret. Got: ${receivedSecret}`);
}

// 4. RETURN CLEAN DATA (Modern fields from trigger-n8n API)
return {
  json: {
    valid: true,
    bookingId: data.bookingId,
    yocoId: data.yocoId,
    paymentStatus: data.paymentStatus || 'paid',
    guest_name: data.guest_name,
    guest_email: data.guest_email,
    guest_phone: data.guest_phone,
    booking_date: data.booking_date,
    start_time: data.start_time,
    end_time: data.end_time,
    simulator_id: data.simulator_id,
    bay_name: data.bay_name,
    time_slot: data.time_slot,
    player_count: data.player_count || 1,
    duration_hours: data.duration_hours || 1,
    session_type: data.session_type || 'quick',
    session_type_label: data.session_type_label || 'Quick Play',
    addon_coaching: data.addon_coaching || false,
    addon_club_rental: data.addon_club_rental || false,
    total_price: data.total_price || data.totalPrice || '0.00',
    amount_paid: data.amount_paid || data.depositPaid || '0.00',
    amount_due: data.amount_due || data.outstandingBalance || '0.00',
    payment_type: data.payment_type || 'deposit',
    is_fully_paid: data.is_fully_paid || false,
    payment_summary: data.payment_summary || ''
  }
};

var booking = $('Validate & Prep').item.json;
var simulatorMap = {1: 'Lounge Bay', 2: 'Middle Bay', 3: 'Window Bay'};
var bayName = booking.bay_name || simulatorMap[booking.simulator_id] || ('Bay ' + booking.simulator_id);

// Add-on rows
var addonRows = [];
if (booking.addon_coaching) addonRows.push(`<tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Coaching Session</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#059669;font-weight:600;text-align:right;">\u2713 Included</td></tr>`);
if (booking.addon_club_rental) addonRows.push(`<tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Club Hire</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#059669;font-weight:600;text-align:right;">\u2713 Included</td></tr>`);
var addonsHtml = addonRows.length > 0 ? addonRows.join('') : '';

// Dynamic payment block
var totalPrice = booking.total_price || '0.00';
var amountPaid = booking.amount_paid || '0.00';
var amountDue = booking.amount_due || '0.00';
var isFullyPaid = booking.is_fully_paid || false;

var paymentBlock = '';
if (isFullyPaid) {
  paymentBlock = `<div style="background-color:#ecfdf5;border:1px solid #d1fae5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;"><span style="font-size:13px;color:#065f46;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;">PAYMENT COMPLETE</span><p style="font-size:28px;font-weight:700;color:#065f46;margin:0;">R${totalPrice} Paid in Full</p><div style="margin-top:16px;padding-top:16px;border-top:1px solid rgba(6,95,70,0.1);"><span style="font-size:14px;color:#065f46;font-weight:500;">\u2713 No balance due at venue</span></div></div>`;
} else {
  paymentBlock = `<div style="background-color:#ecfdf5;border:1px solid #d1fae5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;"><span style="font-size:13px;color:#065f46;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;">SECURED VIA DEPOSIT</span><p style="font-size:28px;font-weight:700;color:#065f46;margin:0;">R${amountPaid} Paid</p><div style="margin-top:16px;padding-top:16px;border-top:1px solid rgba(6,95,70,0.1);display:flex;justify-content:center;align-items:center;gap:8px;"><span style="font-size:14px;color:#065f46;font-weight:500;">Balance Due at Venue:</span><span style="font-size:18px;font-weight:700;color:#92400e;">R${amountDue}</span></div></div>`;
}

// Premium Customer Email HTML
var html = `<div style="font-family:sans-serif;max-width:600px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 10px 25px rgba(0,0,0,0.05);"><div style="background-color:#1a472a;background-image:linear-gradient(135deg,#1a472a 0%,#0d2a19 100%);padding:60px 40px;text-align:center;"><div style="display:inline-block;background:rgba(255,255,255,0.1);border:1px solid rgba(255,255,255,0.2);color:#fff;padding:6px 16px;border-radius:100px;font-size:12px;font-weight:600;margin-bottom:20px;">SESSION CONFIRMED</div><p style="color:#fff;font-size:24px;font-weight:800;letter-spacing:-0.5px;margin:0 0 8px;">The Mulligan</p><p style="color:#fbbf24;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:2px;margin:0 0 30px;opacity:0.9;">The Simulator Never Judges</p><h1 style="color:#fff;font-size:32px;font-weight:700;margin:0;line-height:1.2;">You're Teeing Off!</h1><p style="color:#a3d9a5;font-size:16px;margin:12px 0 0;opacity:0.8;">See you on the green, ${booking.guest_name}.</p></div><div style="padding:40px;"><p style="font-size:18px;color:#111827;font-weight:600;margin:0 0 16px;">Exciting news, ${booking.guest_name}!</p><p style="font-size:15px;color:#4b5563;line-height:1.6;margin:0 0 32px;">Your booking at The Mulligan is confirmed. We've reserved the <strong>${bayName}</strong> exclusively for your group. Fasten your spikes and get ready for a world-class indoor golf experience.</p><div style="background-color:#f9fafb;border:1px solid #f3f4f6;border-radius:12px;padding:24px;margin-bottom:32px;"><span style="font-size:12px;font-weight:700;color:#9ca3af;text-transform:uppercase;letter-spacing:1px;margin-bottom:20px;display:block;">Booking Specifications</span><table style="width:100%;border-collapse:collapse;"><tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Date</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;">${booking.booking_date}</td></tr><tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Start Time</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;">${booking.start_time}</td></tr><tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Duration</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;">${booking.duration_hours} Hours</td></tr><tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Bay Location</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;">${bayName}</td></tr><tr><td style="padding:12px 0;font-size:14px;color:#6b7280;text-align:left;">Players</td><td style="padding:12px 0;font-size:14px;color:#111827;font-weight:600;text-align:right;">${booking.player_count} Players</td></tr>${addonsHtml}</table></div>${paymentBlock}<div style="margin-bottom:32px;"><h3 style="font-size:16px;font-weight:700;color:#1a472a;margin:0 0 16px;">Session Prep</h3><div style="margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;"><span style="color:#059669;font-weight:bold;margin-right:10px;">\u2713</span><strong>Arrive 10 mins early</strong> \u2014 Grab a coffee and settle in before tee-off.</div><div style="margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;"><span style="color:#059669;font-weight:bold;margin-right:10px;">\u2713</span><strong>The Gear</strong> \u2014 Club rentals are available at R100/hr, or bring your own free of charge.</div><div style="margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;"><span style="color:#059669;font-weight:bold;margin-right:10px;">\u2713</span><strong>Clean Play</strong> \u2014 Ensure your gear is clean; sharpie marks damage our screens.</div></div><div style="text-align:center;margin-top:40px;"><a href="https://maps.google.com/?q=38A+Chopin+St+Vanderbijlpark" style="display:inline-block;background-color:#1a472a;color:#ffffff;padding:18px 36px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;box-shadow:0 4px 12px rgba(26,71,42,0.2);">Get Directions</a></div></div><div style="background-color:#f9fafb;padding:40px;text-align:center;border-top:1px solid #f3f4f6;"><div style="color:#1a472a;font-size:18px;font-weight:800;margin-bottom:12px;">The Mulligan</div><div style="font-size:13px;color:#9ca3af;margin-bottom:24px;line-height:1.5;">38A Chopin St, Vanderbijlpark S.W. 5<br>Gauteng, South Africa</div><div style="font-size:11px;color:#9ca3af;">&copy; 2025 The Mulligan Golf Lounge. All rights reserved.</div></div></div>`;

return {
  json: {
    from: "The Mulligan <bookings@themulligan.org>",
    to: [booking.guest_email],
    subject: `\u2705 Booking Confirmed: ${booking.booking_date} at ${booking.start_time}`,
    html: html
  }
};

var booking = $('Validate & Prep').item.json;
var simulatorMap = {1: 'Lounge Bay', 2: 'Middle Bay', 3: 'Window Bay'};
var bayName = booking.bay_name || simulatorMap[booking.simulator_id] || ('Bay ' + booking.simulator_id);

// Add-on rows for store
var addonRows = [];
if (booking.addon_coaching) addonRows.push(`<tr><td style="padding:8px 0;color:#6b7280;">Coaching</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#059669;">\u2713 Booked</td></tr>`);
if (booking.addon_club_rental) addonRows.push(`<tr><td style="padding:8px 0;color:#6b7280;">Club Hire</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#059669;">\u2713 Booked</td></tr>`);
var addonsHtml = addonRows.length > 0 ? `<tr><td colspan="2" style="padding-top:10px;"><div style="font-size:12px;color:#9ca3af;text-transform:uppercase;margin-bottom:5px;">Add-ons</div><table style="width:100%;border-collapse:collapse;">${addonRows.join('')}</table></td></tr>` : '';

// Use MODERN financial fields from trigger-n8n API
var totalPrice = booking.total_price || '0.00';
var amountPaid = booking.amount_paid || '0.00';
var amountDue = booking.amount_due || '0.00';
var isFullyPaid = booking.is_fully_paid || false;
var paymentSummary = booking.payment_summary || '';

// Dynamic payment status label
var paymentLabel = isFullyPaid ? 'PAID IN FULL' : 'DEPOSIT RECEIVED';
var balanceColor = isFullyPaid ? '#15803d' : '#b45309';
var balanceText = isFullyPaid ? 'R0.00' : `R${amountDue}`;

// Store Notification HTML
var html = `<div style="font-family:'Helvetica Neue',Arial,sans-serif;max-width:600px;margin:0 auto;color:#1f2937;line-height:1.5;"><div style="background-color:#1a472a;padding:30px;text-align:center;border-radius:12px 12px 0 0;"><h1 style="color:#ffffff;margin:0;font-size:24px;letter-spacing:1px;">BOOKING ALERT</h1><p style="color:#a3d9a5;margin:5px 0 0 0;font-size:12px;text-transform:uppercase;">Store Operations Notification</p></div><div style="padding:30px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;background-color:#ffffff;"><div style="margin-bottom:25px;"><h2 style="font-size:14px;color:#6b7280;text-transform:uppercase;letter-spacing:1px;margin-bottom:15px;border-bottom:1px solid #f3f4f6;padding-bottom:5px;">\ud83d\udc64 Guest Details</h2><table style="width:100%;border-collapse:collapse;"><tr><td style="padding:8px 0;color:#6b7280;">Name</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.guest_name || 'N/A'}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Phone</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.guest_phone || 'N/A'}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Email</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.guest_email || 'N/A'}</td></tr></table></div><div style="background-color:#f9fafb;border-radius:8px;padding:20px;margin-bottom:25px;"><h2 style="font-size:14px;color:#6b7280;text-transform:uppercase;letter-spacing:1px;margin-bottom:15px;border-bottom:1px solid #e5e7eb;padding-bottom:5px;">\ud83d\udd52 Session Info</h2><table style="width:100%;border-collapse:collapse;"><tr><td style="padding:8px 0;color:#6b7280;">Date</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.booking_date || 'N/A'}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Time</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.start_time || 'N/A'}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Duration</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.duration_hours || 0} Hours</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Bay</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#1a472a;">${bayName}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Players</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">${booking.player_count || 0} Players</td></tr>${addonsHtml}</table></div><div style="border:2px solid #e5e7eb;border-radius:8px;padding:20px;"><h2 style="font-size:14px;color:#6b7280;text-transform:uppercase;letter-spacing:1px;margin-bottom:15px;">\ud83d\udcb0 Financial Summary</h2><table style="width:100%;border-collapse:collapse;"><tr><td style="padding:8px 0;color:#6b7280;">Total Amount</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#111827;">R${totalPrice}</td></tr><tr><td style="padding:8px 0;color:#6b7280;">Paid Online</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#15803d;">R${amountPaid}</td></tr><tr style="font-size:18px;"><td style="padding:15px 0 0 0;border-top:2px solid #e5e7eb;font-weight:800;color:#111827;">BALANCE DUE</td><td style="padding:15px 0 0 0;border-top:2px solid #e5e7eb;text-align:right;font-weight:800;color:${balanceColor};">${balanceText}</td></tr></table><div style="margin-top:12px;padding:10px;background-color:#f0fdf4;border-radius:6px;text-align:center;"><span style="font-size:12px;font-weight:600;color:#065f46;text-transform:uppercase;letter-spacing:0.5px;">${paymentLabel}</span></div></div><div style="margin-top:30px;text-align:center;"><a href="https://themulligan.org/admin" style="display:inline-block;background-color:#1a472a;color:#ffffff;padding:15px 30px;border-radius:8px;text-decoration:none;font-weight:700;font-size:14px;box-shadow:0 4px 6px rgba(0,0,0,0.1);">OPEN ADMIN DASHBOARD</a></div><p style="margin-top:25px;font-size:12px;color:#9ca3af;text-align:center;">This is an automated operational notification.<br>The Mulligan Golf Lounge</p></div></div>`;

return {
  json: {
    from: "The Mulligan <bookings@themulligan.org>",
    to: ["themulligan.store@gmail.com"],
    subject: `\u26f3 NEW BOOKING: ${booking.guest_name || 'New Guest'} - ${bayName} @ ${booking.start_time}`,
    html: html
  }
};
